const translations = {
  en,
  es: deepMerge(JSON.parse(JSON.stringify(en)), esOverrides),
  fr: deepMerge(JSON.parse(JSON.stringify(en)), frOverrides),
  de: deepMerge(JSON.parse(JSON.stringify(en)), deOverrides),
  it: deepMerge(JSON.parse(JSON.stringify(en)), itOverrides),
  pt: deepMerge(JSON.parse(JSON.stringify(en)), ptOverrides),
  zh: deepMerge(JSON.parse(JSON.stringify(en)), zhOverrides),
  ja: deepMerge(JSON.parse(JSON.stringify(en)), jaOverrides),
  ko: deepMerge(JSON.parse(JSON.stringify(en)), koOverrides),
  ar: deepMerge(JSON.parse(JSON.stringify(en)), arOverrides),
  ru: deepMerge(JSON.parse(JSON.stringify(en)), ruOverrides),
};

const LanguageContext = createContext();

export function LanguageProvider({ children }) {
  const [lang, setLang] = useState(() => {
    try {
      return localStorage.getItem(LANG_STORAGE_KEY) || 'en';
    } catch {
      return 'en';
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem(LANG_STORAGE_KEY, lang);
      document.documentElement.lang = lang;
      document.documentElement.dir = ['ar'].includes(lang) ? 'rtl' : 'ltr';
    } catch (e) {}
  }, [lang]);

  const t = (path) => {
    const keys = path.split('.');
    let obj = translations[lang] || en;
    for (const k of keys) {
      obj = obj?.[k];
    }
    if (obj != null) return obj;
    obj = en;
    for (const k of keys) {
      obj = obj?.[k];
    }
    return obj ?? path;
  };

  const value = { lang, setLang, t, translations: translations[lang] || en };

  return (
    <LanguageContext.Provider value={value}>
      {children}
    </LanguageContext.Provider>
  );
}

export function useLanguage() {
  const ctx = useContext(LanguageContext);
  if (!ctx) throw new Error('useLanguage must be used within LanguageProvider');
  return ctx;
}
